import{_ as a,o as i,c as n,a as e}from"./chunks/framework.8tiMeCK-.js";const l="/PenguinLab/assets/ch05_fig048.D32zm7Ed.webp",g=JSON.parse('{"title":"5.4  配置 Generic KASAN 模式","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch05_4.md","filePath":"notes/linux_kernel_debugging/ch05_4.md","lastUpdated":null}'),t={name:"notes/linux_kernel_debugging/ch05_4.md"};function p(r,s,o,h,d,c){return i(),n("div",null,[...s[0]||(s[0]=[e('<h1 id="_5-4-配置-generic-kasan-模式" tabindex="-1">5.4 配置 Generic KASAN 模式 <a class="header-anchor" href="#_5-4-配置-generic-kasan-模式" aria-label="Permalink to &quot;5.4  配置 Generic KASAN 模式&quot;">​</a></h1><p>既然决定了先拿 Generic KASAN 开刀，那我们就得先把内核「武装」起来。</p><p>配置过程本身并不复杂，但就像是给赛车换引擎——虽然只是拧几个螺丝，但你知道这几个螺丝拧下去之后，这台机器的运行逻辑就全变了。</p><h3 id="启用-generic-kasan" tabindex="-1">启用 Generic KASAN <a class="header-anchor" href="#启用-generic-kasan" aria-label="Permalink to &quot;启用 Generic KASAN&quot;">​</a></h3><p>第一步是常规操作：打开内核配置菜单。</p><p>如果你是在为 ARM64 配置（这也是我们演示的默认架构），命令如下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ARCH=arm64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> menuconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在菜单里，你需要按以下路径导航，找到 KASAN 的开关： <code>Kernel hacking</code> → <code>Memory Debugging</code> → <code>KASAN: runtime memory debugger</code></p><p>进入这个子菜单后，你会看到模式选择的选项。这里我们保持默认，也就是 <strong>Generic KASAN</strong> 模式。</p><p><img src="'+l+`" alt="Kernel Configuration Menu"><em>图 5.1 – 启用 KASAN 的内核配置截图</em></p><p>当你把光标停在 <code>Config KASAN as generic mode</code> 这一项上时，按下 <code>&lt; Help &gt;</code> 键，屏幕上会弹出一段值得你花 10 秒钟读完的提示。这不仅是说明，这是它在向你索要「代价」：</p><blockquote><p>This mode consumes about 1/8th of available memory at kernel start and introduces an overhead of ~x1.5 for the rest of the allocations. The performance slowdown is ~x3.</p></blockquote><p>翻译成人话就是：</p><ol><li><strong>内存</strong>：内核启动时，它会直接吃掉你 <strong>1/8</strong> 的物理内存。如果你的板子只有 512MB 内存，这刀下去是很痛的。</li><li><strong>分配开销</strong>：所有的内存分配开销都会增加约 <strong>1.5 倍</strong>。</li><li><strong>整体性能</strong>：系统运行速度会慢上 <strong>3 倍</strong>左右。</li></ol><p>这就是你为了捕捉那些幽灵般的 Bug 所支付的首付。</p><p>保存配置并退出后，我们可以看看 <code>.config</code> 文件里到底发生了什么变化。</p><p>对于 ARM64 架构，<code>.config</code> 里会出现一组特定的宏（注意 <code>SHADOW_OFFSET</code> 和 <code>SW_TAGS</code> 的出现）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KASAN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .config</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_KASAN_SHADOW_OFFSET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0xdfffffd000000000</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_HAVE_ARCH_KASAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_HAVE_ARCH_KASAN_SW_TAGS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_CC_HAS_KASAN_GENERIC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_KASAN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_KASAN_GENERIC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这里面有一个关键信息：<code>CONFIG_KASAN_SHADOW_OFFSET</code>。 这就是我们之前说的「影子内存」的基地址（Kernel Virtual Address）。内核会依靠这个值，把你的实际内存地址映射到这片专门的影子区域上，以此记录每一段内存的状态（是否可读、是否已释放等）。</p><hr><h3 id="kasan-对编译过程的影响" tabindex="-1">KASAN 对编译过程的影响 <a class="header-anchor" href="#kasan-对编译过程的影响" aria-label="Permalink to &quot;KASAN 对编译过程的影响&quot;">​</a></h3><p>启用 <code>CONFIG_KASAN=y</code> 后，仅仅配置是不够的，编译器的行为也会发生根本性的变化。</p><p>如果你带着 <code>V=1</code> 参数重新编译内核（<code>make V=1</code>），你会看到满屏飞舞的 GCC 参数。如果我们截取其中一段，你会看到类似这样的编译命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> V=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Wp,-MMD,[...]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsanitize=kernel-address</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-fasan-shadow-offset=0xdffffc0000000000 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--param</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">asan-globals=1 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--param</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> asan-instrumentation-with-call-threshold=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--param </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">asan-stack=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --param</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> asan-instrument-allocas=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>请注意这几个关键参数：</p><ul><li><strong><code>-fsanitize=kernel-address</code></strong>：这就是编译器插桩的总开关。它告诉 GCC：「在这个编译单元里，我要对所有的内存访问进行检查」。</li><li><strong><code>-fasan-shadow-offset=...</code></strong>：告诉编译器，影子内存的起始偏移量是多少，这样它生成的检查代码才能算出正确的影子地址。</li></ul><p><strong>KASAN 的工作原理本质上就是：每当你读写内存时，它都要插手管一管。</strong></p><p>这里用到了一种叫 <strong>Compile-Time Instrumentation (编译时插桩)</strong> 的技术。简单来说，编译器会在编译阶段，在你的代码里偷偷塞入一些「检查代码」。</p><p>每当你有一行代码试图读取 1、2、4、8 或 16 字节的内存时，编译器实际上会生成类似这样的逻辑：</p><ol><li>调用 <code>__asan_load*()</code> 函数（Outline 模式）</li><li>或者直接插入一段检查逻辑（Inline 模式）</li></ol><p>通过检查对应的「影子内存」里的值，运行时就能判断：这次访问是合法的，还是我们在「越界读写」。</p><h4 id="outline-vs-inline-插桩的两种流派" tabindex="-1">Outline vs. Inline：插桩的两种流派 <a class="header-anchor" href="#outline-vs-inline-插桩的两种流派" aria-label="Permalink to &quot;Outline vs. Inline：插桩的两种流派&quot;">​</a></h4><p>既然提到了插桩，这里有一个重要的配置选项值得你关注，它决定了编译器插手的「深度」。</p><p>在配置菜单里，你会看到 <strong><code>Instrumentation type</code></strong> 选项。 它对应两个内核配置宏：</p><ul><li><strong><code>CONFIG_KASAN_OUTLINE</code></strong>（默认）：<strong>轮廓化插桩</strong>。 <ul><li>编译器插入的是真正的<strong>函数调用</strong>（比如 <code>__asan_load1</code>）。</li><li><strong>优点</strong>：生成的内核镜像体积<strong>更小</strong>（检查代码只有一份）。</li><li><strong>缺点</strong>：每次访问都要走一遍函数调用流程，性能损耗相对较高。</li></ul></li><li><strong><code>CONFIG_KASAN_INLINE</code></strong>：<strong>内联插桩</strong>。 <ul><li>编译器直接把检查的<strong>逻辑代码</strong>硬拷贝到每一次内存访问的地方。</li><li><strong>优点</strong>：<strong>速度更快</strong>（省去了函数调用的开销），通常比 Outline 快 1.1 到 2 倍。</li><li><strong>缺点</strong>：内核镜像体积会<strong>显著膨胀</strong>（因为检查代码被复制了无数遍）。</li></ul></li></ul><p>这是典型的工程 trade-off（权衡）。对于调试内核来说，通常默认的 Outline 模式就够用了；但如果你觉得 KASAN 太慢影响了某些时序相关的 Bug 复现，尝试切换到 Inline 模式可能会带来惊喜。</p><hr><h3 id="辅助配置-让报告更易读" tabindex="-1">辅助配置：让报告更易读 <a class="header-anchor" href="#辅助配置-让报告更易读" aria-label="Permalink to &quot;辅助配置：让报告更易读&quot;">​</a></h3><p>KASAN 捕捉到 Bug 时会抛出一份报告。为了让这份报告更有含金量，不仅仅是告诉你「崩了」，而是告诉你「是谁干的」，建议你顺手开启以下两个选项。</p><h4 id="_1-开启堆栈跟踪" tabindex="-1">1. 开启堆栈跟踪 <a class="header-anchor" href="#_1-开启堆栈跟踪" aria-label="Permalink to &quot;1. 开启堆栈跟踪&quot;">​</a></h4><p>务必开启 <code>CONFIG_STACKTRACE</code>。</p><p>这会让 KASAN 在报告错误时，不仅打印出当前的访问栈，还会打印出「这块内存是什么时候被分配的」以及「是什么时候被释放的」。这对于定位 <code>Use-After-Free</code>（释放后重用）问题至关重要。</p><h4 id="_2-追踪页面所有者-page-owner" tabindex="-1">2. 追踪页面所有者 (Page Owner) <a class="header-anchor" href="#_2-追踪页面所有者-page-owner" aria-label="Permalink to &quot;2. 追踪页面所有者 (Page Owner)&quot;">​</a></h4><p>在 <code>Kernel hacking</code> → <code>Memory Debugging</code> 菜单下，找到并开启 <code>Track page owner</code>（对应 <code>CONFIG_PAGE_OWNER</code>）。</p><p>这不仅用于 KASAN，它是一个通用的内核内存调试功能，能记录每一个物理页面的分配和释放历史栈。</p><p>⚠️ <strong>注意</strong><code>page_owner</code> 默认是关闭的，即使你编译进去了，也需要在内核启动参数里加上 <code>page_owner=on</code> 才能真正生效。</p><hr><h3 id="x86-64-上的特别选项-vmalloc-空间" tabindex="-1">x86_64 上的特别选项：vmalloc 空间 <a class="header-anchor" href="#x86-64-上的特别选项-vmalloc-空间" aria-label="Permalink to &quot;x86_64 上的特别选项：vmalloc 空间&quot;">​</a></h3><p>如果你是在 x86_64 架构上配置，你会发现一个 ARM64 上通常没有的额外选项：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Back mappings in vmalloc space with real shadow memory</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个选项的作用是：用真实的影子内存来<strong>映射 vmalloc 空间</strong>。</p><p>开启它，KASAN 就能检测到 vmalloc 相关的内存破坏问题（比如越界写入了 vmalloc 分配的区域）。代价自然是运行时内存占用的进一步增加。如果你在调试驱动模块（它们经常加载在 vmalloc 空间），这个选项非常有用。</p><hr><h3 id="准备点火" tabindex="-1">准备点火 <a class="header-anchor" href="#准备点火" aria-label="Permalink to &quot;准备点火&quot;">​</a></h3><p>理论就先到这里。</p><p>现在的任务是：按照上面的步骤，配置并重新构建你的「调试版内核」。</p><p>把它编译出来，烧录进去，然后重启。当系统成功启动并看到那个熟悉的 login 提示符时——虽然它可能比平时慢了那么几拍——你就拥有了一双透视眼，准备好去抓那些隐藏在阴暗角落里的内存 Bug 了。</p>`,57)])])}const u=a(t,[["render",p]]);export{g as __pageData,u as default};
